solution.code:
def has_cycle(graph):
    visited = set()
    stack = set()
    def dfs(u):
        visited.add(u)
        stack.add(u)
        for v in graph.get(u, []):
            if v in stack: return True
            if v not in visited and dfs(v): return True
        stack.remove(u)
        return False
    return any(node not in visited and dfs(node) for node in graph)

if __name__ == "__main__":
    graph = {0: [1, 2], 1: [2], 2: []}
    print(f"Has Cycle: {has_cycle(graph)}")
